
import { defineComponent } from "vue";
import { NSpace, NSpin } from "naive-ui";

export default defineComponent({
  name: "EnvlopeA",
  components: {
    NSpace,
    NSpin,
  },
  data() {
    return {
      show: false,
      envelopMove: "close",
      loadingTexts: [" ", ".", ".."],
      loadingHuas: [
        "正在整理思绪",
        "正在紧张不已",
        "正在调整情绪",
        "准备完毕！",
      ],
      loadingText: "",
      nowHua: 0,
      nowText: 0,
    };
  },
  methods: {
    async EnvelopeOperator() {
      if (this.envelopMove == "close") {
        this.envelopMove = "open";
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        await setTimeout(() => {
          console.log("准备加载信封...");
          this.show = !this.show;
          setTimeout(() => {
            console.log("准备打开信封...");
            this.showText();
          }, 1000 * 5);
        }, 1000 * 5);
      } else if (this.envelopMove == "open") {
        this.envelopMove = "close";
      }
    },
    showText() {
      setTimeout(() => {
        let h = this.loadingHuas[this.nowHua];
        if (h == undefined) return;
        let t = this.loadingTexts[this.nowText];
        t = t == undefined ? "..." : t;
        this.loadingText = h + t;
        console.log(this.loadingText);
        if (this.nowText == this.loadingTexts.length) {
          this.nowHua++;
          this.nowText = 0;
        }
        if (this.nowHua == this.loadingHuas.length) {
          setTimeout(() => {
            this.show = !this.show;
            // this.nowHua = 0;
            // this.nowText = 0;
            this.$router.push("/lover");
          }, 1000 * 2);
        }
        this.nowText++;

        this.showText();
      }, 1000 * 2);
    },
  },
});
